HTML_ROOT = ROOT / "generated_html_full"
HEADERS = ["来源","商品中文名称","型号","产品名称（英文）","URL","简介","产品详情","代码","网站分类","主图","详情图","图片文件名","alt text","title","Caption","价格","💲","是否上传"]

def esc(x):
    return html.escape(str(x), quote=True)

def slug(s):
    return re.sub(r"[^A-Za-z0-9]+", "_", s).strip("_")[:100] or "item"

def table(headers, rows):
    th = "".join(f'<th style="background:#111;color:#fff;border:1px solid #111;padding:11px 12px;text-align:left;">{esc(h)}</th>' for h in headers)
    body = []
    for r in rows:
        tds = []
        for i, c in enumerate(r):
            weight = "font-weight:700;" if i == 0 else ""
            tds.append(f'<td style="border:1px solid #d7d7d7;padding:10px 12px;{weight}vertical-align:top;">{esc(c)}</td>')
        body.append("<tr>" + "".join(tds) + "</tr>")
    return f'<table style="border-collapse:collapse;border:1px solid #111;font-size:14px;" border="0" width="100%" cellspacing="0" cellpadding="0"><thead><tr>{th}</tr></thead><tbody>{"".join(body)}</tbody></table>'

def section(title, body):
    return f'<table style="margin-bottom:34px;" border="0" width="100%" cellspacing="0" cellpadding="0"><tbody><tr><td style="border-left:5px solid #111;padding-left:15px;padding-bottom:12px;"><h2 style="margin:0;font-size:18px;color:#111;text-transform:uppercase;font-weight:800;">{esc(title)}</h2></td></tr><tr><td style="padding-top:18px;">{body}</td></tr></tbody></table>'

def page(title, model, ptype, overview, features, specs, ordering, accessories=None, note=None):
    parts = [f'<!-- Atomfair Complete Product HTML - Full-English Release --><div style="width:100%;background:#ffffff;padding:0;" align="center"><table style="width:100%;font-family:Arial,Helvetica,sans-serif;color:#333;line-height:1.58;background:#fff;" border="0" width="100%" cellspacing="0" cellpadding="0"><tbody><tr><td style="padding:38px 20px;border-bottom:4px solid #111;"><h1 style="margin:0;font-size:26px;color:#111;font-weight:800;text-transform:uppercase;">{esc(title)}</h1><div style="margin-top:8px;font-size:14px;color:#333;">Product Type: {esc(ptype)}</div><div class="model" style="margin-top:10px;font-size:15px;color:#333;font-weight:700;">Atomfair Model: {esc(model)}</div><div style="margin-top:15px;display:inline-block;background:#111;color:#fff;padding:6px 15px;font-size:13px;font-weight:bold;letter-spacing:.6px;text-transform:uppercase;">Research-grade laboratory instrument</div></td></tr><tr><td style="padding:38px 20px;">']
    parts.append(section("Product Overview", "".join(f'<p style="margin:0 0 14px 0;font-size:15px;color:#444;text-align:justify;">{esc(p)}</p>' for p in overview)))
    parts.append(section("Key Features and Advantages", '<ul style="margin:0;padding-left:22px;font-size:14px;color:#444;line-height:1.85;">' + "".join(f'<li style="margin-bottom:9px;">{esc(f)}</li>' for f in features) + "</ul>"))
    parts.append(section("Technical Specifications", table(["Parameter", "Specification / Available Values"], specs)))
    if accessories:
        parts.append(section("Included and Compatible Accessories", table(["Accessory / Module", "Reference Code", "Specification", "Compatibility / Use"], accessories)))
    parts.append(section("Atomfair Product Ordering and Configuration Table", table(ordering[0], ordering[1])))
    note = note or "All product parameters, configuration values, dimensions, capacities and compatible accessory information are preserved in structured tables. Each product specification or accessory receives a separate Atomfair order model."
    parts.append(f'<table style="background:#f7f7f7;border:1px solid #e0e0e0;margin-bottom:34px;" border="0" width="100%" cellspacing="0" cellpadding="22"><tbody><tr><td style="font-size:14px;color:#333;"><div style="margin-bottom:10px;"><strong>Data Handling Standard:</strong> {esc(note)}</div><div><strong>Ordering Standard:</strong> Do not merge different capacities, channel counts, module positions, bath volumes or accessory types into one order line.</div></td></tr></tbody></table></td></tr><tr><td style="padding:25px 20px;background:#111;text-align:center;"><div style="color:#fff;font-size:20px;font-weight:bold;margin-bottom:8px;letter-spacing:1px;">TAILORED SOLUTIONS FOR RESEARCH</div><div style="color:#ddd;font-size:13px;margin-bottom:18px;">For bulk orders, OEM requirements, accessory matching, platform selection or configuration confirmation, contact our engineering sales team.</div><div style="display:inline-block;background:#fff;color:#111;padding:12px 35px;font-weight:800;font-size:13px;text-transform:uppercase;letter-spacing:1px;border-radius:2px;">EMAIL: inquiry@atomfair.com</div></td></tr><tr><td style="padding:28px 20px;text-align:center;font-size:12px;color:#888;letter-spacing:1px;"><div style="margin-bottom:5px;text-transform:uppercase;"><strong>Supplier:</strong> Atomfair</div><div style="text-transform:uppercase;"><strong>Brand:</strong> ATOMFAIR&reg;</div></td></tr></tbody></table></div>')
    return "".join(parts)

def intro_from(overview):
    return " ".join(overview)

def record(cn, model, en, intro, code, cat):
    row = {h: "" for h in HEADERS}
    row.update({"来源": "", "商品中文名称": cn, "型号": model, "产品名称（英文）": en, "简介": intro, "代码": code, "网站分类": cat})
    return row

def emit_series(series_key, sheet, products):
    out = HTML_ROOT / series_key
    out.mkdir(parents=True, exist_ok=True)
    records = []
    for p in products:
        code = page(p["en"], p["model"], p["ptype"], p["overview"], p["features"], p["specs"], p["ordering"], p.get("accessories"))
        (out / f'{slug(p["model"])}.html').write_text(code, encoding="utf-8")
        records.append(record(p["cn"], p["model"], p["en"], intro_from(p["overview"]), code, p["cat"]))
    path = ROOT / f"{series_key}_records.json"
    path.write_text(json.dumps([{"sheetName": sheet, "folder": str(out), "records": records}], ensure_ascii=False, indent=2), encoding="utf-8")
    return path, records

def mk_product(cn, model, en, ptype, overview, features, specs, cat, accessories=None):
    ordering = (["Unique Atomfair Order Model", "Source Model / Item", "Key Specification", "Primary Application"], [[model, en.split()[-1], specs[0][1] if specs else "", ptype]])
    return {"cn": cn, "model": model, "en": en, "ptype": ptype, "overview": overview, "features": features, "specs": specs, "ordering": ordering, "cat": cat, "accessories": accessories}

